<section class="admin-page-head"><div><p class="eyebrow">MARKETING</p><h1>Cupoane și promoții</h1></div></section><div class="admin-two-columns"><section class="coupon-grid"><?php foreach($items as $item): $displayValue=$item['discount_type']==='fixed'?number_format((int)$item['discount_value']/100,2,'.',''):(int)$item['discount_value']; ?><form class="admin-panel" method="post" action="<?= e(url('/admin/cupoane')) ?>"><?= csrf_field() ?><span class="status-pill <?= $item['is_active']?'success':'' ?>"><?= $item['is_active']?'Activ':'Inactiv' ?></span><h2><?= e($item['code']) ?></h2><input type="hidden" name="code" value="<?= e($item['code']) ?>"><label>Tip<select name="discount_type"><option value="percent" <?= $item['discount_type']==='percent'?'selected':'' ?>>Procent</option><option value="fixed" <?= $item['discount_type']==='fixed'?'selected':'' ?>>Sumă fixă</option></select></label><label>Valoare<input type="number" step="0.01" name="discount_value" min="0.01" value="<?= e($displayValue) ?>" required></label><label>Minim comandă (lei)<input type="number" step="0.01" name="minimum_order" min="0" value="<?= number_format((int)$item['minimum_order_minor']/100,2,'.','') ?>"></label><label class="check-label"><input type="checkbox" name="is_active" value="1" <?= $item['is_active']?'checked':'' ?>> Cupon activ</label><button class="admin-button" type="submit">Salvează</button></form><?php endforeach; ?></section><aside><form class="admin-panel" method="post" action="<?= e(url('/admin/cupoane')) ?>"><?= csrf_field() ?><h2>Cupon nou</h2><label>Cod<input name="code" required></label><label>Tip<select name="discount_type"><option value="percent">Procent</option><option value="fixed">Sumă fixă</option></select></label><label>Valoare<input type="number" step="0.01" name="discount_value" min="0.01" required></label><label>Minim comandă (lei)<input type="number" step="0.01" name="minimum_order" min="0" value="0"></label><label class="check-label"><input type="checkbox" name="is_active" value="1" checked> Cupon activ</label><button class="admin-button" type="submit">Salvează cuponul</button></form></aside></div>